+        let left = handle_index;
+        let right = handle_index + 1;
+        let sizes = self.ctx.sizes.get();
+        let total = sizes.iter().copied().sum::<f64>().max(1.0);
+        let to_percent = |value: f64| {
+            if self.ctx.size_unit == SizeUnit::Percent {
