    pub fn on_handle_pointermove(&self, pos: f64) {
        (self.send)(Event::DragMove { pos });
    }

    /// Dispatches handle pointer-up intent.
    pub fn on_handle_pointerup(&self) {
        (self.send)(Event::DragEnd);
