    /// Dispatches handle focus intent.
    pub fn on_handle_focus(&self, handle_index: usize) {
        (self.send)(Event::HandleFocus { handle_index });
    }

    /// Dispatches handle blur intent.
    pub fn on_handle_blur(&self) {
        (self.send)(Event::HandleBlur);
    }

