                Some(TransitionPlan::new())
            }
            (State::Idle, Event::SetSizes { sizes }) => {
                let sizes = clamp_all(sizes, &ctx.panels, ctx.sizes.get());
                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
                    commit_sizes(ctx, sizes);
                }))
